SELECT , s.supplier_name AS supplierName, g.goods_name AS goodsName, AS userName FROM purchase_order p LEFT JOIN supplier s ON p.supplier_id = s.id LEFT JOIN goods g ON p.goods_id = g.id LEFT JOIN user u ON p.user_id = u.id
and p.status = #{status}
ORDER BY p.buy_time DESC

SELECT
,
s.supplier_name AS supplierName,
g.goods_name AS goodsName,
 AS userName
FROM purchase_order p
LEFT JOIN supplier s ON p.supplier_id = s.id
LEFT JOIN goods g ON p.goods_id = g.id
LEFT JOIN user u ON p.user_id = u.id


        and p.status = #{status}


        and p.goods_id = #{goodsId}


        and p.supplier_id = #{supplierId}


        and p.user_id = #{userId}


        and p.buy_time between #{buyTimeStart} and #{buyTimeEnd}


ORDER BY p.buy_time DESC
